mapper.select:
SELECT id, title, content, writer, views, created_at
FROM board
WHERE id = #{id}

SELECT id, title, content, writer, views, created_at FROM board
AND title LIKE CONCAT('%', #{title}, '%')
AND writer = #{writer}
AND created_at >= #{fromDate}
AND created_at < DATE_ADD(#{toDate}, INTERVAL 1 DAY)
ORDER BY id DESC LIMIT 20

SELECT id, title, content, writer, views, created_at
FROM board


        AND title LIKE CONCAT('%', #{search.title}, '%')


        AND writer = #{search.writer}


        AND created_at >= #{search.fromDate}


        AND created_at < DATE_ADD(#{search.toDate}, INTERVAL 1 DAY)


        AND (
        created_at < #{cursorCreatedAt}
        OR (created_at = #{cursorCreatedAt} AND id < #{cursorId})
        )


ORDER BY created_at DESC, id DESC
LIMIT #{limit}

mapper.update:
UPDATE board
SET views = views + 1
WHERE id = #{id}

